using Microsoft.EntityFrameworkCore;
using PokeBinder.TcgCatalog.DbContext;
using PokeBinder.TcgCatalog.DbContext.Entities;

namespace PokeBinder.ETL.Db.Repositories;

public class FilterOptionUpsertService(TcgCatalogDbContext dbContext)
{
    public void SeedAll()
    {
        SeedGenerationFilterOptions();
        SeedPokemonFilterOptions();
        SeedCardTypeFilterOptions();
        SeedRarityBySetFilterOptions();

        Console.WriteLine("All filter option seed data upserted.");
    }

    private void SeedGenerationFilterOptions()
    {
        var generations = new List<GenerationFilterOption>
        {
            new() { Id = 1, Name = "Generation I" },
            new() { Id = 2, Name = "Generation II" },
            new() { Id = 3, Name = "Generation III" },
            new() { Id = 4, Name = "Generation IV" },
            new() { Id = 5, Name = "Generation V" },
            new() { Id = 6, Name = "Generation VI" },
            new() { Id = 7, Name = "Generation VII" },
            new() { Id = 8, Name = "Generation VIII" },
            new() { Id = 9, Name = "Generation IX" },
        };

        dbContext.GenerationFilterOptions.UpsertRange(generations).On(g => g.Id).Run();

        Console.WriteLine("Generation filter options seeded.");
    }

    private void SeedPokemonFilterOptions()
    {
        var pokemon = GetAllPokemon();

        dbContext.PokemonFilterOptions
            .UpsertRange(pokemon)
            .On(p => p.Id)
            .Run();

        Console.WriteLine("Pokemon filter options seeded.");
    }

    private void SeedCardTypeFilterOptions()
    {
        var cardTypes = GetCardTypes().ToList();

        dbContext.CardTypeFilterOptions.UpsertRange(cardTypes).On(c => c.Id).Run();

        Console.WriteLine("Card type filter options seeded.");
    }

    private void SeedRarityBySetFilterOptions()
    {
        var raritiesBySet = dbContext.Cards
            .Where(c => c.Rarity != null && c.Rarity != "")
            .Select(c => new { c.SetId, c.Rarity })
            .Distinct()
            .ToList();

        var filterOptions = raritiesBySet
            .Select(r => new RarityBySetFilterOption
            {
                SetId = r.SetId!.Value,
                Rarity = r.Rarity!
            })
            .ToList();

        dbContext.RarityBySetFilterOptions
            .UpsertRange(filterOptions)
            .On(r => new { r.SetId, r.Rarity })
            .Run();

        Console.WriteLine("Rarity by set filter options seeded.");
    }

